using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public float MicroAccuracy { get; set; }
    public float MacroAccuracy { get; set; }
    public float LogLoss { get; set; }
    public float LogLossReduction { get; set; }
    public PerClassMetric[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetric
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _classLabels;
    private readonly EvaluationResponse _evaluationMetrics;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract class labels from the trained model's key-value mapping
        var transformedData = _model.Transform(dataView);
        var labelColumn = transformedData.Schema["Label"];
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref labelBuffer);
        _classLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        // Evaluate using the training data (small dataset)
        var predictions = _model.Transform(dataView);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        _evaluationMetrics = new EvaluationResponse
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = metrics.PerClassPrecision
                .Zip(metrics.PerClassRecall, (p, r) => new { Precision = p, Recall = r })
                .Select((m, i) => new PerClassMetric
                {
                    Class = i < _classLabels.Length ? _classLabels[i] : $"Class {i}",
                    Precision = m.Precision,
                    Recall = m.Recall
                })
                .ToArray()
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var prediction = _predictionEngine.Predict(new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        });

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < _classLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_classLabels[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }

    public EvaluationResponse GetMetrics() => _evaluationMetrics;
}

